# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import machine
import time
import network
from umqtt.simple import MQTTClient

WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

BROKER_IP = "192.168.1.100"
CLIENT_ID = "esp32_temp_sensor_01"
TOPIC = b"sensors/temp"
PUBLISH_INTERVAL = 5

def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 0
        while not wlan.isconnected():
            time.sleep(1)
            timeout += 1
            if timeout > 20:
                print("WiFi connection failed!")
                machine.reset()
    print("WiFi connected:", wlan.ifconfig())
    return wlan

def read_temperature():
    adc = machine.ADC(machine.Pin(34))
    adc.atten(machine.ADC.ATTN_11DB)
    adc.width(machine.ADC.WIDTH_12BIT)
    
    raw_value = adc.read()
    voltage = raw_value * (3.3 / 4095)
    temperature = voltage * 100.0
    
    return round(temperature, 2)

def connect_mqtt():
    client = MQTTClient(CLIENT_ID, BROKER_IP)
    try:
        client.connect()
        print("Connected to MQTT broker at", BROKER_IP)
        return client
    except Exception as e:
        print("MQTT connection failed:", e)
        return None

def main():
    wlan = connect_wifi()
    
    client = connect_mqtt()
    if client is None:
        print("Failed to connect to MQTT broker. Restarting...")
        time.sleep(5)
        machine.reset()
    
    print("Starting sensor data publishing...")
    print("Topic:", TOPIC)
    print("Interval:", PUBLISH_INTERVAL, "seconds")
    
    while True:
        try:
            temperature = read_temperature()
            
            payload = '{"client_id": "%s", "temperature": %.2f, "unit": "C"}' % (
                CLIENT_ID, temperature
            )
            
            client.publish(TOPIC, payload)
            print("Published: %s -> %s" % (TOPIC.decode(), payload))
            
            time.sleep(PUBLISH_INTERVAL)
            
        except OSError as e:
            print("Connection error:", e)
            print("Reconnecting to MQTT broker...")
            time.sleep(2)
            try:
                client = connect_mqtt()
                if client is None:
                    print("Reconnection failed. Restarting...")
                    time.sleep(5)
                    machine.reset()
            except Exception as e2:
                print("Reconnection exception:", e2)
                time.sleep(5)
                machine.reset()
                
        except Exception as e:
            print("Unexpected error:", e)
            time.sleep(2)

if __name__ == "__main__":
    main()